import React, { useEffect, useState } from 'react';
import axios from 'axios';

const Home = () => {
    const [songs, setSongs] = useState([]);
    const [currentSong, setCurrentSong] = useState(null);

    // 1. Lấy danh sách bài hát từ Server khi mở trang
    useEffect(() => {
        const fetchSongs = async () => {
            try {
                const res = await axios.get('http://localhost:5000/api/songs');
                setSongs(res.data);
            } catch (err) {
                console.error("Lỗi lấy danh sách nhạc:", err);
            }
        };
        fetchSongs();
    }, []);

    return (
        <div style={{ padding: '20px', maxWidth: '800px', margin: '0 auto' }}>
            <h2 style={{ textAlign: 'center', color: '#333' }}>DANH SÁCH BÀI HÁT</h2>
            
            <div style={{ display: 'grid', gap: '15px' }}>
                {songs.length === 0 ? <p>Chưa có bài hát nào được tải lên.</p> : 
                    songs.map((song) => (
                        <div key={song._id} style={{
                            display: 'flex', 
                            alignItems: 'center', 
                            padding: '10px', 
                            border: '1px solid #ddd', 
                            borderRadius: '8px',
                            background: currentSong?._id === song._id ? '#e3f2fd' : '#fff'
                        }}>
                            {/* Ảnh bìa bài hát */}
                            <img 
                                src={song.imageUrl ? `http://localhost:5000${song.imageUrl}` : 'https://via.placeholder.com/50'} 
                                alt="cover" 
                                style={{ width: '50px', height: '50px', borderRadius: '4px', marginRight: '15px', objectFit: 'cover' }}
                            />
                            
                            <div style={{ flex: 1 }}>
                                <div style={{ fontWeight: 'bold' }}>{song.title}</div>
                                <div style={{ fontSize: '14px', color: '#666' }}>{song.artist}</div>
                            </div>

                            <button 
                                onClick={() => setCurrentSong(song)}
                                style={{ padding: '8px 15px', cursor: 'pointer', background: '#28a745', color: '#fff', border: 'none', borderRadius: '4px' }}
                            >
                                PLAY
                            </button>
                        </div>
                    ))
                }
            </div>

            {/* TRÌNH PHÁT NHẠC CỐ ĐỊNH Ở DƯỚI */}
            {currentSong && (
                <div style={{
                    position: 'fixed', bottom: 0, left: 0, right: 0, 
                    background: '#333', color: '#fff', padding: '15px', 
                    display: 'flex', flexDirection: 'column', alignItems: 'center'
                }}>
                    <div>Đang phát: <b>{currentSong.title}</b> - {currentSong.artist}</div>
                    <audio 
                        src={`http://localhost:5000${currentSong.songUrl}`} 
                        controls 
                        autoPlay 
                        style={{ marginTop: '10px', width: '100%' }}
                    />
                </div>
            )}
            <div style={{ height: '100px' }}></div> {/* Khoảng trống để không bị đè bởi trình phát nhạc */}
        </div>
    );
};

export default Home;
